local coreModules={"chat_config","feedback_config","registry","esp_base","esp_axe","esp_runner","esp_cuirassier","esp_barrel","esp_lantern","esp_normal","esp_driver","esp_player_ctrl","esp_player_render","esp_player_events","esp_fort","hitbox","killaura","pvp","features","commands","getitems","hud"}

local function loadMod(m)
  local c=MODS["core/"..m]
  if not c then return nil end
  local w="_G.BFH=_G.BFH or {};_G.BFH.Core=_G.BFH.Core or {};"..c
  local fn,err=loadstring(w)
  if not fn then warn("[BFH] core/"..m.." ERR: "..tostring(err));return nil end
  local ok,M=pcall(fn)
  if ok and type(M)=="table" then return M
  elseif not ok then warn("[BFH] core/"..m.." FAIL: "..tostring(M)) end
  return nil
end

for _,x in ipairs(coreModules)do
  local M=loadMod(x)
  if M then _G.BFH.Core[x:upper()]=M end
end

if MODS.ui then
  local fn,err=loadstring(MODS.ui)
  if fn then pcall(fn)else warn("[BFH] ui ERR: "..tostring(err))end
end

if MODS.bridge then
  local fn,err=loadstring(MODS.bridge)
  if fn then pcall(fn)else warn("[BFH] bridge ERR: "..tostring(err))end
end

